const body = $input.first().json.body;

// Validar input mínimo
if (!body.guion || body.guion.trim().length < 10) {
  throw new Error('Guion requerido (mínimo 10 caracteres)');
}

const clips = body.clips_urls || [];
const clipList = clips.length > 0
  ? clips.map((url, i) => `clip_${i+1}.mp4 (${url})`).join('\n')
  : 'stock_001.mp4 (Pexels API)\nstock_002.mp4 (Pexels API)\nstock_003.mp4 (Pexels API)';

const duracion = body.duracion || 60;
const jobId = Math.random().toString(36).slice(2, 10).toUpperCase();

return [{
  jobId,
  guion: body.guion,
  estilo: body.estilo || 'ensayo',
  duracion,
  plan: body.plan || 'estandar',
  cliente_email: body.cliente_email || '',
  clipList,
  frames: duracion * 30,
  timestamp: new Date().toISOString()
}];

