const claudeResponse = $input.first().json;
const rawText = claudeResponse.content[0].text;

// Limpiar y parsear JSON
const clean = rawText.replace(/```json|```/g, '').trim();
let config;
try {
  config = JSON.parse(clean);
} catch (e) {
  throw new Error('Claude no generó JSON válido: ' + rawText.slice(0, 200));
}

// Agregar datos del job
const prevData = $('⚙️ Preparar Input').first().json;
const plan = prevData.plan;
const prices = { eco: 0.35, estandar: 0.50, industrial: 0.20 };
const price = prices[plan] || 0.50;

config.job = {
  id: prevData.jobId,
  plan,
  price,
  cost: 0.005,
  margin: Math.round(price / 0.005) + 'x',
  cliente_email: prevData.cliente_email,
  timestamp: prevData.timestamp,
  coherenceScore: config.meta?.coherence_score || 0,
};

console.log(`Job ${prevData.jobId} — Coherence: ${config.meta?.coherence_score}/100 — ${config.scenes?.length} escenas`);

return [config];

// Generar factura y mensaje de entrega
const renderResult = $input.first().json;
const jobConfig = $('📋 Parsear JSON').first().json;

const invoice = {
  jobId: jobConfig.job.id,
  plan: jobConfig.job.plan,
  precio: jobConfig.job.price,
  costoReal: jobConfig.job.cost,
  margen: jobConfig.job.margin,
  video: renderResult.outputUrl || `https://refineria.s3.amazonaws.com/videos/${jobConfig.job.id}.mp4`,
  coherenceScore: jobConfig.job.coherenceScore,
  keyMessage: jobConfig.meta?.key_message || '',
  emotionArc: (jobConfig.meta?.emotion_arc || []).join(' → '),
  mensaje: `Tu chatarra ha sido refinada con éxito.\n\n🎬 Video listo: ${renderResult.outputUrl}\n\n💰 Tarifa de Reciclaje Digital aplicada: $${jobConfig.job.price}\n📊 Coherencia narrativa: ${jobConfig.job.coherenceScore}/100\n🔮 Mensaje central: ${jobConfig.meta?.key_message || ''}\n\n♻️ La Refinería Digital — Donde otros ven ruido, nosotros destilamos claridad.`,
};

return [invoice];

